import"./hoisted.NF3yKIiG.js";document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".product-card-add-btn").forEach(d=>{d.addEventListener("click",o=>{const a=o.currentTarget,t=JSON.parse(a.dataset.product||"{}");if(window.addToCartGlobal){const e=t.id||t.url?.split("/").pop()||t.title.replace(/\s+/g,"-").toLowerCase();window.addToCartGlobal({...t,id:e,quantity:1})}})})});
